# Example: handling text editor tool calls in an agentic loop
import anthropic

client = anthropic.Anthropic()

TEXT_EDITOR_TOOL = {
    "name": "str_replace_based_edit_tool",
    "type": "text_editor_20250429"
}

def run_code_editor_agent(task: str, system: str) -> str:
    """Run an agent that can edit files using the text editor tool."""
    messages = [{"role": "user", "content": task}]
    # Simulated file system for the agent
    files = {}

    while True:
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=4096,
            system=system,
            tools=[TEXT_EDITOR_TOOL],
            messages=messages
        )

        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            for block in reversed(response.content):
                if hasattr(block, "text"):
                    return block.text
            return ""

        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue

            cmd = block.input.get("command")
            path = block.input.get("path", "")

            if cmd == "create":
                files[path] = block.input.get("file_text", "")
                result = {"success": True, "message": f"Created {path}"}

            elif cmd == "view":
                if path not in files:
                    result = {"error": f"File not found: {path}"}
                else:
                    content = files[path]
                    start = block.input.get("view_range", [1, None])[0] - 1
                    end = block.input.get("view_range", [1, None])[1]
                    lines = content.splitlines()
                    selected = lines[start:end]
                    numbered = "\n".join(f"{i+start+1}\t{l}" for i, l in enumerate(selected))
                    result = {"content": numbered}

            elif cmd == "str_replace":
                if path not in files:
                    result = {"error": f"File not found: {path}"}
                else:
                    old = block.input.get("old_str", "")
                    new = block.input.get("new_str", "")
                    content = files[path]
                    count = content.count(old)
                    if count == 0:
                        result = {"error": "old_str not found in file. Check for whitespace differences."}
                    elif count > 1:
                        result = {"error": f"old_str found {count} times. Make it more specific."}
                    else:
                        files[path] = content.replace(old, new, 1)
                        result = {"success": True}
            else:
                result = {"error": f"Unknown command: {cmd}"}

            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": str(result)
            })

        messages.append({"role": "user", "content": tool_results})
